import React from "react";
import './Contact.css';

function Contact() {
    return (
        <div className="contact">
            <h1>Contact Us</h1>
            <p>This is the contact page of our website.</p>
            <p>You can reach us at contact@example.com</p>
        </div>
    );
}

export default Contact;
